// // This module implements a 1-to-2 demultiplexer instead of a 2-to-1 multiplexer.
module mux_2to1(a, b, sel, y);

    input a;
    input b;
    input sel;
    output y;
    reg y;

    always @(*)
        begin
            if (sel == 0)
                y = a;
            else
                y = b;
        end

endmodule
